// NODO 1 — Ingest GLOBAL + Normalize + Dedup  (mode: Run Once for All Items)
// 7 fuentes legales (APIs/feeds). Prefiltro por sector. Dedup entre dias (workflowStaticData, 30d).

const http = (opts) => this.helpers.httpRequest(opts);
const staticData = this.getWorkflowStaticData('global');

// --- Sector de Jorge (CV 2026) ---
const KEYWORDS = ['cloud architect','cloud engineer','platform engineer','platform architect',
  'devops','sre','site reliability','terraform','terragrunt','kubernetes','aks','eks',
  'aws','azure','gcp','mlops','llmops','ai infrastructure','ai platform','gpu','nvidia',
  'infrastructure as code','solutions architect','agentic','rag'];

const ADZUNA_ID  = $env.ADZUNA_APP_ID  || '';
const ADZUNA_KEY = $env.ADZUNA_APP_KEY || '';
// "todo el mundo": Adzuna cubre estos paises (1 call c/u). Recorta si quieres menos volumen.
const ADZUNA_COUNTRIES = ['gb','de','fr','es','nl','it','at','ch','pl','us','ca','au','in','sg'];

async function safe(name, fn){ try { const r = await fn(); console.log(`${name}: ${r.length}`); return r; }
  catch(e){ console.log(`${name} ERROR:`, e.message); return []; } }
const strip = (s)=> (s||'').toString().replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim().slice(0,1000);

let jobs = [];

// 1) Remotive
jobs = jobs.concat(await safe('Remotive', async()=>{
  const r = await http({ url:'https://remotive.com/api/remote-jobs?search=cloud', json:true });
  return (r.jobs||[]).map(j=>({ source:'Remotive', title:j.title, company:j.company_name,
    location:j.candidate_required_location||'Remote', url:j.url, description:strip(j.description), salary:j.salary||'' }));
}));

// 2) RemoteOK
jobs = jobs.concat(await safe('RemoteOK', async()=>{
  const r = await http({ url:'https://remoteok.com/api', json:true, headers:{'User-Agent':'DailyFreelanceHunter/1.0'} });
  return (Array.isArray(r)?r.slice(1):[]).map(j=>({ source:'RemoteOK', title:j.position||j.title, company:j.company,
    location:j.location||'Remote', url:j.url, description:strip(j.description), salary:'' }));
}));

// 3) Arbeitnow (EU)
jobs = jobs.concat(await safe('Arbeitnow', async()=>{
  const r = await http({ url:'https://www.arbeitnow.com/api/job-board-api', json:true });
  return (r.data||[]).map(j=>({ source:'Arbeitnow', title:j.title, company:j.company_name,
    location:j.location||'Remote', url:j.url, description:strip(j.description), salary:'' }));
}));

// 4) Jobicy (remoto global)
jobs = jobs.concat(await safe('Jobicy', async()=>{
  const r = await http({ url:'https://jobicy.com/api/v2/remote-jobs?count=50&tag=devops', json:true });
  return (r.jobs||[]).map(j=>({ source:'Jobicy', title:j.jobTitle, company:j.companyName,
    location:j.jobGeo||'Remote', url:j.url, description:strip(j.jobExcerpt), salary:'' }));
}));

// 5) Himalayas (remoto global)
jobs = jobs.concat(await safe('Himalayas', async()=>{
  const r = await http({ url:'https://himalayas.app/jobs/api?limit=50', json:true });
  return (r.jobs||[]).map(j=>({ source:'Himalayas', title:j.title, company:j.companyName,
    location:(j.locationRestrictions&&j.locationRestrictions.join(', '))||'Remote',
    url:j.applicationLink||j.url||('https://himalayas.app/jobs/'+(j.slug||'')), description:strip(j.description||j.excerpt), salary:'' }));
}));

// 6) The Muse (global, tech categories)
jobs = jobs.concat(await safe('TheMuse', async()=>{
  const r = await http({ url:'https://www.themuse.com/api/public/jobs?category=Data%20and%20Analytics&category=Engineering&page=1', json:true });
  return (r.results||[]).map(j=>({ source:'TheMuse', title:j.name, company:(j.company&&j.company.name)||'',
    location:(j.locations&&j.locations.map(l=>l.name).join(', '))||'', url:(j.refs&&j.refs.landing_page)||'', description:strip(j.contents), salary:'' }));
}));

// 7) Adzuna (agregador multi-pais, requiere key)
if(ADZUNA_ID && ADZUNA_KEY){
  for(const c of ADZUNA_COUNTRIES){
    jobs = jobs.concat(await safe('Adzuna-'+c, async()=>{
      const r = await http({ url:`https://api.adzuna.com/v1/api/jobs/${c}/search/1`,
        qs:{ app_id:ADZUNA_ID, app_key:ADZUNA_KEY, what_or:'cloud architect terraform kubernetes devops platform sre',
             results_per_page:30, 'content-type':'application/json' }, json:true });
      return (r.results||[]).map(j=>({ source:'Adzuna-'+c.toUpperCase(), title:j.title,
        company:(j.company&&j.company.display_name)||'', location:(j.location&&j.location.display_name)||'',
        url:j.redirect_url, description:strip(j.description),
        salary:j.salary_min?`${Math.round(j.salary_min)}-${Math.round(j.salary_max)}`:'' }));
    }));
  }
}

// --- PREMIUM: 10 empresas TOP del sector (ATS oficiales) — freelance O fijo ---
// Edita token si alguna empresa cambia de ATS. Todas envueltas en safe() => si una falla, sigue.
const PREMIUM = [
  { name:'Anthropic',    provider:'greenhouse', token:'anthropic' },
  { name:'Databricks',   provider:'greenhouse', token:'databricks' },
  { name:'HashiCorp',    provider:'greenhouse', token:'hashicorp' },
  { name:'Hugging Face', provider:'greenhouse', token:'huggingface' },
  { name:'GitLab',       provider:'greenhouse', token:'gitlab' },
  { name:'Elastic',      provider:'greenhouse', token:'elastic' },
  { name:'Canonical',    provider:'greenhouse', token:'canonical' },
  { name:'OpenAI',       provider:'ashby',      token:'openai' },
  { name:'Cohere',       provider:'ashby',      token:'cohere' },
  { name:'Scale AI',     provider:'lever',      token:'scaleai' },
];
async function fetchATS(c){
  if(c.provider==='greenhouse'){
    const r = await http({ url:`https://boards-api.greenhouse.io/v1/boards/${c.token}/jobs?content=true`, json:true });
    return (r.jobs||[]).map(j=>({ source:'🏆 '+c.name, premium:true, title:j.title, company:c.name,
      location:(j.location&&j.location.name)||'', url:j.absolute_url, description:strip(j.content), salary:'' }));
  }
  if(c.provider==='lever'){
    const r = await http({ url:`https://api.lever.co/v0/postings/${c.token}?mode=json`, json:true });
    return (Array.isArray(r)?r:[]).map(j=>({ source:'🏆 '+c.name, premium:true, title:j.text, company:c.name,
      location:(j.categories&&j.categories.location)||'', url:j.hostedUrl, description:strip(j.descriptionPlain||j.description), salary:'' }));
  }
  if(c.provider==='ashby'){
    const r = await http({ url:`https://api.ashbyhq.com/posting-api/job-board/${c.token}`, json:true });
    return (r.jobs||[]).map(j=>({ source:'🏆 '+c.name, premium:true, title:j.title, company:c.name,
      location:j.location||'', url:j.jobUrl||j.applyUrl, description:strip(j.descriptionPlain||j.description), salary:'' }));
  }
  return [];
}
for(const c of PREMIUM){ jobs = jobs.concat(await safe('Premium:'+c.name, ()=>fetchATS(c))); }

// Prefiltro por sector (barato, antes de gastar tokens) — aplica a todas (incl. premium en tu sector)
jobs = jobs.filter(j=>{ const t=((j.title||'')+' '+(j.description||'')).toLowerCase();
  return KEYWORDS.some(k=>t.includes(k)); });

// Dedup en el run + entre dias (caduca 30d)
staticData.seen = staticData.seen || {};
const now = Date.now();
for(const k in staticData.seen){ if(now - staticData.seen[k] > 2592000000) delete staticData.seen[k]; }

const within = new Set(); const out = [];
for(const j of jobs){
  if(!j.title) continue;
  const key = ((j.url||'') || ((j.title||'')+'|'+(j.company||''))).toLowerCase().trim();
  if(!key || within.has(key) || staticData.seen[key]) continue;
  within.add(key); staticData.seen[key] = now;
  out.push(j);
}

console.log(`TOTAL nuevas tras dedup: ${out.length}`);
return out.map(j=>({ json:j }));

// NODO 2 — AI Score (Haiku, por lotes) + Draft (Sonnet) + Calibracion + Premium
// Devuelve: premium (empresas top, freelance O fijo), shortlist (resto con borrador), more (tabla).

const KEY  = $env.ANTHROPIC_API_KEY;
const http = (opts) => this.helpers.httpRequest(opts);

const MODEL_SCORE = 'claude-haiku-4-5';   // verifica IDs vigentes en tu cuenta
const MODEL_DRAFT = 'claude-sonnet-4-5';

const THRESHOLD = 65;   // match minimo para notificar (no aplica a premium)
const DRAFT_TOP = 10;   // borradores para el resto (no-premium)
const PREM_TOP  = 15;   // cuantas premium mostrar
const PREM_DRAFT= 6;    // borradores para premium
const MAX_SCORE = 220;
const CHUNK     = 50;

const PROFILE = `Jorge Aguirre Romero — Senior Cloud & AI Platform Architect (Madrid, remote, EU/US, open to relocation).
15 years international IT, 5+ years enterprise cloud architecture.
NOW: co-owner of Mercedes-Benz mAzure HUB; principal architect of "Minerva", their NVIDIA AI factory.
CORE: Azure, AWS; Terraform/Terragrunt; GitLab CI/CD; multi-tenant Kubernetes AKS/EKS; GPU (NVIDIA NGC/CUDA, GPU Operator); hybrid networking; Grafana/Prometheus.
AI: Agentic & multi-agent RAG (LangChain/LangGraph, LlamaIndex, Anthropic SDK), guardrails, evals.
REGULATED: Automotive, Pharma (GxP/21 CFR Part 11), Healthcare (HIPAA), Banking.
PROOF: 30% AWS cost cut via IaC. Languages: ES native, EN C1, DE A2.
RATE: freelance day-rate floor 295 EUR + VAT (target 450-600). Prefer contract OR undisclosed rate.`;

const items = $input.all().map(i=>i.json);
if(!KEY){ throw new Error('Falta ANTHROPIC_API_KEY en variables de entorno de n8n'); }
if(items.length===0){ return [{ json:{ total:0, premium:[], shortlist:[], more:[] } }]; }

async function anthropic(model, system, user, maxTokens){
  const r = await http({ method:'POST', url:'https://api.anthropic.com/v1/messages', json:true,
    headers:{ 'x-api-key':KEY, 'anthropic-version':'2023-06-01', 'content-type':'application/json' },
    body:{ model, max_tokens:maxTokens, system, messages:[{ role:'user', content:user }] } });
  return r.content[0].text;
}
const parseArr = (txt)=>{ const m = txt.match(/\[[\s\S]*\]/); return m ? JSON.parse(m[0]) : []; };

// ---- CALIBRACION: aprende tu gusto (feedback 👍/👎) ----
const SB_URL = $env.SUPABASE_URL;
const SB_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
async function fbExamples(v){
  if(!SB_URL || !SB_KEY) return [];
  try{
    const r = await http({ url:`${SB_URL}/rest/v1/jobs?feedback=eq.${v}&select=title,company,location&order=created_at.desc&limit=12`,
      headers:{ apikey:SB_KEY, Authorization:`Bearer ${SB_KEY}` }, json:true });
    return Array.isArray(r) ? r : [];
  }catch(e){ console.log('feedback fetch fail:', e.message); return []; }
}
const liked = await fbExamples('up');
const disliked = await fbExamples('down');
const fmt = (a)=> a.map(x=>`- ${x.title} @ ${x.company||'?'} (${x.location||'?'})`).join('\n');
const CAL = (liked.length || disliked.length)
  ? `\n\nCALIBRATION — learn from past feedback. Boost similar to LIKED, penalize similar to DISLIKED.\nLIKED:\n${fmt(liked)||'(none)'}\nDISLIKED:\n${fmt(disliked)||'(none)'}`
  : '';
console.log(`Calibracion: ${liked.length} 👍 / ${disliked.length} 👎`);

// ---- 1) SCORING por lotes (Haiku) ----
const pool = items.slice(0, MAX_SCORE);
const scoreSys = `You score how well freelance/contract jobs match a candidate. Return ONLY a JSON array, no prose. `+
`Each: {"i":<index>,"score":<0-100>,"reason":"<max 12 words>"}. `+
`High = senior cloud/platform/devops/SRE/AI-infra/GPU, remote or EU/US, contract-friendly, rate >= floor or undisclosed. `+
`Low = junior, on-site only, unrelated stack, or rate clearly below floor. `+
`IMPORTANT: jobs with "premium":true are at the candidate's TOP target companies — he accepts BOTH freelance/contract AND permanent there; give a strong boost and do NOT penalize full-time/permanent.`;

let allScores = [];
for(let start=0; start<pool.length; start+=CHUNK){
  const batch = pool.slice(start, start+CHUNK).map((j,k)=>({ i:start+k, premium:!!j.premium, title:j.title,
    company:j.company, location:j.location, salary:j.salary, desc:(j.description||'').slice(0,400) }));
  const user = `PROFILE:\n${PROFILE}${CAL}\n\nJOBS (JSON):\n${JSON.stringify(batch)}\n\nReturn the JSON array of scores.`;
  try { allScores = allScores.concat(parseArr(await anthropic(MODEL_SCORE, scoreSys, user, 3000))); }
  catch(e){ console.log('score batch fail @'+start+':', e.message);
    allScores = allScores.concat(batch.map(b=>({ i:b.i, score:b.premium?75:50, reason:'fallback' }))); }
}

const scored = pool.map((j,idx)=>{ const s = allScores.find(x=>x.i===idx) || { score:0, reason:'' };
  return { ...j, score:s.score, reason:s.reason }; });

// Premium: TODAS las de empresas top (sin umbral), por score
const premiumJobs = scored.filter(j=>j.premium).sort((a,b)=>b.score-a.score).slice(0, PREM_TOP);
// Resto: solo >= umbral
let relevant = scored.filter(j=>!j.premium && j.score>=THRESHOLD).sort((a,b)=>b.score-a.score);
if(relevant.length===0 && premiumJobs.length===0){ relevant = scored.sort((a,b)=>b.score-a.score).slice(0,8); }
const shortlist = relevant.slice(0, DRAFT_TOP);
const more = relevant.slice(DRAFT_TOP);

// ---- 2) DRAFTS (Sonnet) para premium top + shortlist (dedup por url) ----
const draftPoolRaw = [...premiumJobs.slice(0, PREM_DRAFT), ...shortlist];
const seenK = new Set(); const draftPool = [];
for(const j of draftPoolRaw){ const k=(j.url||j.title); if(seenK.has(k)) continue; seenK.add(k); draftPool.push(j); }

const draftSys = `You write short freelance/role proposals (max 90 words). Confident, specific, one quantified proof, `+
`end with one question. Real proof: co-owner of Mercedes-Benz mAzure HUB, 30% AWS cost cut, principal architect of NVIDIA AI factory. `+
`Match the job's language. Return ONLY a JSON array: [{"i":<index>,"draft":"..."}].`;
let drafts = [];
if(draftPool.length){
  const dInput = draftPool.map((j,idx)=>({ i:idx, title:j.title, company:j.company, desc:(j.description||'').slice(0,450) }));
  try { drafts = parseArr(await anthropic(MODEL_DRAFT, draftSys, `PROFILE:\n${PROFILE}\n\nJOBS:\n${JSON.stringify(dInput)}\n\nReturn the JSON array of drafts.`, 4000)); }
  catch(e){ console.log('draft fail:', e.message); }
}
const byKey = {};
draftPool.forEach((j,idx)=>{ byKey[j.url||j.title] = (drafts.find(d=>d.i===idx)||{}).draft || null; });
const attach = (j)=>({ ...j, draft: byKey[j.url||j.title] || j.draft || null });

const premiumOut = premiumJobs.map(attach);
const shortlistOut = shortlist.map(attach);

console.log(`Premium: ${premiumOut.length} | shortlist: ${shortlistOut.length} | more: ${more.length}`);
return [{ json:{ total: relevant.length + premiumJobs.length, premium: premiumOut, shortlist: shortlistOut, more } }];

// NODO — Upsert a Supabase (passthrough)  (mode: Run Once for All Items)
// Guarda todas las ofertas en la tabla `jobs` (dedup_key unico) y pasa el item al email.
const http = (opts) => this.helpers.httpRequest(opts);
const URL = $env.SUPABASE_URL;
const KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

const d = $input.first().json;
const all = [].concat(d.premium || [], d.shortlist || [], d.more || []);

if(URL && KEY && all.length){
  const rows = all.map(j=>({
    dedup_key: ((j.url||'') || ((j.title||'')+'|'+(j.company||''))).toLowerCase().trim(),
    source:j.source, title:j.title, company:j.company, location:j.location, url:j.url,
    salary:j.salary, description:(j.description||'').slice(0,2000),
    score:j.score, reason:j.reason, premium: !!j.premium,
    draft: j.draft || undefined   // no sobrescribe drafts existentes si no hay uno nuevo
  }));
  try {
    await http({ method:'POST', url:`${URL}/rest/v1/jobs?on_conflict=dedup_key`, json:true,
      headers:{ apikey:KEY, Authorization:`Bearer ${KEY}`, 'Content-Type':'application/json',
                Prefer:'resolution=merge-duplicates,return=minimal' },
      body: rows });
    console.log('Supabase upsert OK:', rows.length);
  } catch(e){ console.log('Supabase ERROR:', e.message); }
} else {
  console.log('Supabase no configurado o 0 filas — se omite el guardado.');
}

return [{ json: d }]; // passthrough para Build Email

// NODO 4 — Build Email HTML  (mode: Run Once for All Items)
// Seccion 0: 🏆 Empresas TOP. Seccion A: shortlist con borrador. Seccion B: todas las demas.
const d = $input.first().json;
const premium = d.premium || [];
const short   = d.shortlist || [];
const more    = d.more || [];
const today = new Date().toISOString().slice(0,10);
const esc = (s)=> (s||'').toString().replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');

function card(j, n, gold){
  const draftBox = j.draft ? `<div style="background:#f7fafc;border-left:3px solid ${gold?'#F6B73C':'#16C2C2'};padding:10px 12px;margin-top:8px;font-size:12.5px;color:#34465a;white-space:pre-wrap;">${esc(j.draft)}</div>` : '';
  return `
  <div style="border:1px solid ${gold?'#F6D98A':'#e2e8f0'};border-radius:10px;padding:14px 16px;margin:10px 0;${gold?'background:#fffdf5;':''}">
    <div style="font-size:11px;color:${gold?'#9a6b00':'#0d6e74'};font-weight:700;letter-spacing:.04em;">${esc(j.source)} &middot; MATCH ${j.score}</div>
    <div style="font-size:16px;font-weight:800;color:#0A1A2F;margin:3px 0;">${n}. ${esc(j.title)}</div>
    <div style="font-size:13px;color:#5b6b7c;">${esc(j.company)} &middot; ${esc(j.location)}${j.salary?(' &middot; '+esc(j.salary)):''}</div>
    <div style="font-size:12px;color:#8a3b1c;margin:4px 0;font-style:italic;">${esc(j.reason)}</div>
    <a href="${esc(j.url)}" style="display:inline-block;font-size:13px;color:#16C2C2;font-weight:700;text-decoration:none;margin:2px 0;">Ver oferta y aplicar &rarr;</a>
    ${draftBox}
  </div>`;
}

const premiumCards = premium.map((j,i)=>card(j,i+1,true)).join('');
const shortCards   = short.map((j,i)=>card(j,i+1,false)).join('');
const moreRows = more.map((j)=>`
  <tr>
    <td style="padding:6px 8px;border-bottom:1px solid #eef2f7;font-weight:700;color:#0A1A2F;font-size:12px;">${j.score}</td>
    <td style="padding:6px 8px;border-bottom:1px solid #eef2f7;font-size:12px;"><a href="${esc(j.url)}" style="color:#0d6e74;text-decoration:none;">${esc(j.title)}</a></td>
    <td style="padding:6px 8px;border-bottom:1px solid #eef2f7;font-size:12px;color:#5b6b7c;">${esc(j.company)}</td>
    <td style="padding:6px 8px;border-bottom:1px solid #eef2f7;font-size:11px;color:#8a96a3;">${esc(j.source)} &middot; ${esc(j.location)}</td>
  </tr>`).join('');

const moreTable = more.length ? `
  <h3 style="color:#0A1A2F;font-size:15px;margin:22px 16px 6px;">Todas las demas opciones (${more.length})</h3>
  <table style="width:calc(100% - 32px);margin:0 16px;border-collapse:collapse;">
    <tr style="text-align:left;color:#8a96a3;font-size:11px;"><th style="padding:6px 8px;">Match</th><th style="padding:6px 8px;">Puesto</th><th style="padding:6px 8px;">Empresa</th><th style="padding:6px 8px;">Fuente</th></tr>
    ${moreRows}
  </table>` : '';

const premiumBlock = premium.length ? `
  <h3 style="color:#9a6b00;font-size:16px;margin:16px 0 4px;">🏆 Empresas TOP (freelance o fijo) — ${premium.length}</h3>
  ${premiumCards}` : '';

const html = `<div style="font-family:Arial,Helvetica,sans-serif;max-width:720px;margin:auto;background:#fff;">
  <div style="background:linear-gradient(120deg,#0A1A2F,#0d6e74);color:#fff;padding:22px 24px;border-radius:12px 12px 0 0;">
    <div style="font-size:20px;font-weight:800;">Daily Freelance Hunter</div>
    <div style="font-size:13px;color:#9fe6e6;">${today} &middot; ${d.total} oportunidades &middot; ${premium.length} en empresas top</div>
  </div>
  <div style="padding:8px 16px 20px;">
    ${premiumBlock}
    <h3 style="color:#0A1A2F;font-size:15px;margin:18px 0 4px;">Top ${short.length} con borrador listo</h3>
    ${shortCards || '<p style="color:#5b6b7c;padding:12px;">Sin mas ofertas con borrador hoy.</p>'}
    ${moreTable}
    <p style="color:#9aa7b4;font-size:11px;margin-top:22px;">Generado automaticamente. Revisa cada borrador antes de enviar. No se ha aplicado a nada por ti.</p>
  </div>
</div>`;

return [{ json:{ html, subject:`${d.total} ofertas (${premium.length} top) — ${today}` } }];
